import{_ as r,b as h,a as p}from"./chunks/lab-1-7.DbfC4fYR.js";import{_ as d}from"./chunks/lab-1-8.of6EfLsG.js";import{_ as c,C as o,o as g,c as u,a3 as s,G as a,w as k,j as t,a as i}from"./chunks/framework.DBrjlGeB.js";const P=JSON.parse('{"title":"Lab 4 (Supplementary) - Setting Up a New PC","description":"","frontmatter":{"outline":"deep","highlighter":true,"title":"Lab 4 (Supplementary) - Setting Up a New PC"},"headers":[],"relativePath":"labs/lab-04-supplementary.md","filePath":"labs/lab-04-supplementary.md"}'),y={name:"labs/lab-04-supplementary.md"};function b(m,e,C,f,F,w){const n=o("Badge"),l=o("Checklist");return g(),u("div",null,[e[1]||(e[1]=s('<h1 id="lab-04-supplementary-setting-up-a-new-pc" tabindex="-1">Lab 04 (Supplementary) : Setting Up a New PC <a class="header-anchor" href="#lab-04-supplementary-setting-up-a-new-pc" aria-label="Permalink to &quot;Lab 04 (Supplementary) : Setting Up a New PC&quot;">​</a></h1><h2 id="why-this-lab-exists" tabindex="-1">Why This Lab Exists <a class="header-anchor" href="#why-this-lab-exists" aria-label="Permalink to &quot;Why This Lab Exists&quot;">​</a></h2><p>We have moved to a <strong>new lab</strong>, which means you are now sitting in front of a <strong>fresh computer</strong> that has never seen your work before. None of the tools are installed, you are not logged in to <strong>GitHub</strong>, and your code is not on this PC yet.</p><p>The good news: you do <strong>not</strong> start from zero. Back in <a href="./lab-01.html">Lab 01</a> you already:</p><ul><li>created your <strong>GitHub</strong> account, and</li><li><strong>forked</strong> the <code>CP115-Class-Repo</code> into your own account.</li></ul><p>Those two things live on the <strong>GitHub</strong> web server, not on any single computer, so they are still yours. You do <strong>not</strong> need to create a new account and you do <strong>not</strong> need to fork again.</p><p>What you <em>do</em> need to do on this new PC is:</p><ol><li>Install the tools again (<strong>Git</strong>, <strong>VS Code</strong>, the <strong>Python</strong> extension, <strong>Flowgorithm</strong>, <strong>GitHub CLI</strong>).</li><li>Log in to <strong>GitHub</strong> from the terminal.</li><li><strong>Clone</strong> your existing fork down to this computer.</li><li>Confirm everything works.</li></ol><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>This lab is a setup lab, not new material. Once you finish it you will be ready to continue with the actual <a href="./lab-04.html">Lab 04 - Selection in Flowgorithm</a>. Nothing here replaces Lab 04, it only gets your new PC ready for it.</p></div><h2 id="step-1-install-the-tools" tabindex="-1">Step 1: Install the Tools <a class="header-anchor" href="#step-1-install-the-tools" aria-label="Permalink to &quot;Step 1: Install the Tools&quot;">​</a></h2><p>Follow the <a href="./installation.html">Installation guide</a> to install each tool. You have done this before on the old PC, so it should be quick this time. Install them in this order:</p><ol><li><strong>Git</strong> — <a href="./installation.html#git">installation steps</a></li><li><strong>VS Code</strong> — <a href="./installation.html#vs-code">installation steps</a></li><li>The <strong>Python</strong> extension by <strong>Microsoft</strong> — open the <code>Extensions</code> panel in <strong>VS Code</strong> and install it, exactly as in <a href="./lab-01.html#install-git-and-vs-code">Lab 01</a>.</li><li><strong>Flowgorithm</strong> — <a href="./installation.html#flowgorithm">installation steps</a></li></ol><p align="center"><img src="'+r+'" alt="drawing" width="400"></p><div class="warning custom-block"><p class="custom-block-title">REMINDER</p><p>Do not skip the <strong>Python</strong> extension. Without it, <strong>VS Code</strong> will not highlight your code, autocomplete, or run <strong>Python</strong> files properly.</p></div><h2 id="step-2-prepare-your-workspace-folder" tabindex="-1">Step 2: Prepare Your Workspace Folder <a class="header-anchor" href="#step-2-prepare-your-workspace-folder" aria-label="Permalink to &quot;Step 2: Prepare Your Workspace Folder&quot;">​</a></h2><p>Just like the first time, make a home for your work on this PC so your files are easy to find.</p>',16)),a(n,{type:"tip",text:"Task"}),e[2]||(e[2]=s('<ol><li>Go to the <strong>Desktop</strong>.</li><li>Right-click an empty area and choose <code>New</code> → <code>Folder</code>.</li><li>Name it after yourself, for example <code>aiman-cp115</code>.</li></ol><p>Then open it in <strong>VS Code</strong>:</p><ol><li>Open <strong>VS Code</strong>.</li><li>Click <code>File</code> → <code>Open Folder...</code>.</li><li>Select the folder you just made and click <code>Select Folder</code>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also right-click the folder on the <strong>Desktop</strong> and choose <code>Open with Code</code>.</p></div><h2 id="step-3-install-and-log-in-to-github-cli" tabindex="-1">Step 3: Install and Log In to GitHub CLI <a class="header-anchor" href="#step-3-install-and-log-in-to-github-cli" aria-label="Permalink to &quot;Step 3: Install and Log In to GitHub CLI&quot;">​</a></h2><p>This new PC does not know who you are yet. We use <a href="./glossary.html#github-cli"><strong>GitHub CLI</strong></a> (<code>gh</code>) to authenticate so that cloning, pushing, and pulling all work without typing your password every time.</p><p>Open a terminal in <strong>VS Code</strong> with <code>Terminal</code> → <code>New Terminal</code>.</p><p align="center"><img src="'+d+`" alt="drawing" width="400"></p><p>Install <strong>GitHub CLI</strong> with <a href="./glossary.html#winget"><code>winget</code></a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">winget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GitHub.cli</span></span></code></pre></div><p>Close and reopen the terminal, then verify it installed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>You should see a version number.</p><h3 id="log-in-as-yourself" tabindex="-1">Log In as Yourself <a class="header-anchor" href="#log-in-as-yourself" aria-label="Permalink to &quot;Log In as Yourself&quot;">​</a></h3><p>Because this is a <strong>shared lab PC</strong>, always check first whether someone is already logged in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>If it shows <strong>someone else&#39;s</strong> account, log them out before logging in as yourself:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logout</span></span></code></pre></div><p>Now log in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>Follow the prompts:</p><ul><li>Select <strong>GitHub.com</strong></li><li>Select <strong>HTTPS</strong></li><li>Choose <strong>Login with a web browser</strong></li><li>Copy the one-time code, press <kbd style="color:#fff;background:#0047A3;border:1px solid #0060CC;padding:4px 10px;border-radius:6px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.45),0 1px 3px rgba(0,0,0,.25);font-size:.85em;line-height:1;user-select:none;">Enter</kbd> to open the browser, paste the code, and authorise the app</li></ul><p>Confirm you are in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>You should see <strong>your own</strong> username.</p><h3 id="set-up-your-identity" tabindex="-1">Set Up Your Identity <a class="header-anchor" href="#set-up-your-identity" aria-label="Permalink to &quot;Set Up Your Identity&quot;">​</a></h3><p>Tell <strong>Git</strong> who you are on this PC so your commits are recorded under your name. Replace <code>USERNAME</code> and <code>EMAIL</code> with your real <strong>GitHub</strong> username and email:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;USERNAME&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;EMAIL&quot;</span></span></code></pre></div><h2 id="step-4-sync-your-fork" tabindex="-1">Step 4: Sync Your Fork <a class="header-anchor" href="#step-4-sync-your-fork" aria-label="Permalink to &quot;Step 4: Sync Your Fork&quot;">​</a></h2><p>Your fork may be behind the class repo if the <code>upstream</code> repo was updated while you were away. Bring it up to date <strong>before</strong> you clone, so the copy you download onto this PC is already the latest version.</p><p><a href="./lab-01.html#syncing-fork">Sync your fork</a> on the <strong>GitHub</strong> website: open your fork, click <code>Sync Fork</code>, then <code>Update branch</code>.</p><p align="center"><img src="`+h+'" alt="drawing" width="400"></p><h2 id="step-5-clone-your-existing-fork" tabindex="-1">Step 5: Clone Your Existing Fork <a class="header-anchor" href="#step-5-clone-your-existing-fork" aria-label="Permalink to &quot;Step 5: Clone Your Existing Fork&quot;">​</a></h2><p>Your fork already exists on <strong>GitHub</strong> from <a href="./lab-01.html#forking-the-repository">Lab 01</a>. We are <strong>not</strong> forking again. We only need to bring that fork down to this new computer, and that is exactly what <a href="./glossary.html#clone">cloning</a> does. Because you just synced it, the clone will already contain the latest work, so there is no need to pull afterwards.</p><p>On <strong>GitHub</strong>, open <strong>your own</strong> fork of <code>CP115-Class-Repo</code>, click the green <code>Code</code> button, and copy the link.</p><p align="center"><img src="'+p+'" alt="drawing" width="400"></p><p>Back in <strong>VS Code</strong>, make sure the terminal is inside your workspace folder, then clone using the link you copied (replace it with your own):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/YOUR-USERNAME/CP115-Class-Repo.git</span></span></code></pre></div><p>Press <kbd style="color:#fff;background:#0047A3;border:1px solid #0060CC;padding:4px 10px;border-radius:6px;box-shadow:inset 0 -2px 0 rgba(0,0,0,.45),0 1px 3px rgba(0,0,0,.25);font-size:.85em;line-height:1;user-select:none;">Enter</kbd> and <strong>Git</strong> downloads a full copy of your repository into a new folder.</p><div class="warning custom-block"><p class="custom-block-title">REMINDER</p><p>Make sure you clone <strong>your own</strong> fork, not the original <code>JSK-KML/CP115-Class-Repo</code> and not a classmate&#39;s. Since many students share this PC, double-check the link points to <code>YOUR-USERNAME</code> before you clone.</p></div><h2 id="checklist-before-you-continue" tabindex="-1">Checklist Before You Continue <a class="header-anchor" href="#checklist-before-you-continue" aria-label="Permalink to &quot;Checklist Before You Continue&quot;">​</a></h2>',41)),a(l,{title:"New PC Setup Complete?"},{default:k(()=>[...e[0]||(e[0]=[t("ol",null,[t("li",null,"Git, VS Code, the Python extension, and Flowgorithm are installed on this PC."),t("li",null,[i("You are logged in to GitHub in the terminal as yourself ("),t("code",null,"gh auth status"),i(" shows your username).")]),t("li",null,"You have synced your fork on GitHub."),t("li",null,"You have cloned your own fork onto this computer.")],-1)])]),_:1}),e[3]||(e[3]=s('<p>Once every box is ticked, your new PC is ready. You can now move on to the actual <a href="./lab-04.html">Lab 04 - Selection in Flowgorithm</a>.</p><h2 id="before-you-leave-the-shared-pc" tabindex="-1">Before You Leave the Shared PC <a class="header-anchor" href="#before-you-leave-the-shared-pc" aria-label="Permalink to &quot;Before You Leave the Shared PC&quot;">​</a></h2><p>This is a shared PC. Log out so the next student does not accidentally push to your repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logout</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">REMINDER</p><p>Always run <code>gh auth logout</code> before you leave. If you stay logged in, the next student using this PC could accidentally push their work to your account.</p></div>',5))])}const _=c(y,[["render",b]]);export{P as __pageData,_ as default};
